// ─── Register form ─────────────────────────────────────────────────────────────
function RegisterForm({ onSuccess }) {
  const [email, setEmail]       = useState("")
  const [password, setPassword] = useState("")
  const [error, setError]       = useState("")
  const [pending, start]        = useTransition()

  const submit = e => {
    e.preventDefault(); setError("")
    if (!email || !password) return setError("Please fill in all fields.")
    if (password.length < 8) return setError("Password must be at least 8 characters.")
    start(async () => {
      const r = await apiRegister(email, password)
      r.ok ? onSuccess() : setError(r.error ?? "Something went wrong.")
    })
  }

  return (
    <form onSubmit={submit} style={{ display:"flex", flexDirection:"column", gap:"2vh" }}>
      <Field label="Email address" type="email" placeholder="ada@email.com" value={email}
        onChange={e => setEmail(e.target.value)} autoComplete="email" disabled={pending} />
      <Field label="Password" type="password" placeholder="Min. 8 characters" value={password}
        onChange={e => setPassword(e.target.value)} autoComplete="new-password" disabled={pending} />

      {error && (
        <p className="text-red-500 bg-red-50 border border-red-100 rounded-[1vh] px-[2vh] py-[1.2vh]"
          style={{ fontSize:"clamp(11px,1.3vh,13px)" }}>{error}</p>
      )}

      <button type="submit" disabled={pending}
        className="w-full flex items-center justify-center gap-2 font-semibold text-white rounded-[1.2vh] transition-all disabled:opacity-60"
        style={{ padding:"1.5vh 2vh", fontSize:"clamp(12px,1.5vh,14px)", background:"#7C3AED", boxShadow:"0 4px 16px rgba(124,58,237,0.35)", marginTop:"0.5vh" }}>
        {pending ? <><Spinner /> Creating account…</> : "Create Account"}
      </button>

      <p className="text-center text-[#9B91B5]" style={{ fontSize:"clamp(10px,1.2vh,12px)" }}>
        By signing up you agree to our{" "}
        <a href="#" className="text-[#7C3AED] hover:underline underline-offset-2">Terms</a>
        {" "}and{" "}
        <a href="#" className="text-[#7C3AED] hover:underline underline-offset-2">Privacy Policy</a>
      </p>
    </form>
  )
}

// ─── Login form ────────────────────────────────────────────────────────────────
function LoginForm({ onSuccess }) {
  const [email, setEmail]       = useState("")
  const [password, setPassword] = useState("")
  const [error, setError]       = useState("")
  const [pending, start]        = useTransition()

  const submit = e => {
    e.preventDefault(); setError("")
    if (!email || !password) return setError("Please fill in all fields.")
    start(async () => {
      const r = await apiLogin(email, password)
      r.ok ? onSuccess() : setError(r.error ?? "Invalid email or password.")
    })
  }

  const google = () => {
    start(async () => {
      const r = await apiGoogle()
      r.ok ? onSuccess() : setError("Google sign-in failed.")
    })
  }

  return (
    <form onSubmit={submit} style={{ display:"flex", flexDirection:"column", gap:"2vh" }}>
      <Field label="Email address" type="email" placeholder="you@email.com" value={email}
        onChange={e => setEmail(e.target.value)} autoComplete="email" disabled={pending} />

      <div style={{ display:"flex", flexDirection:"column", gap:"0.8vh" }}>
        <Field label="Password" type="password" placeholder="Your password" value={password}
          onChange={e => setPassword(e.target.value)} autoComplete="current-password" disabled={pending} />
        <div className="flex justify-end">
          <a href="#" className="text-[#7C3AED] hover:underline underline-offset-2 font-medium"
            style={{ fontSize:"clamp(10px,1.2vh,12px)" }}>Forgot password?</a>
        </div>
      </div>

      {error && (
        <p className="text-red-500 bg-red-50 border border-red-100 rounded-[1vh] px-[2vh] py-[1.2vh]"
          style={{ fontSize:"clamp(11px,1.3vh,13px)" }}>{error}</p>
      )}

      <button type="submit" disabled={pending}
        className="w-full flex items-center justify-center gap-2 font-semibold text-white rounded-[1.2vh] transition-all disabled:opacity-60"
        style={{ padding:"1.5vh 2vh", fontSize:"clamp(12px,1.5vh,14px)", background:"#7C3AED", boxShadow:"0 4px 16px rgba(124,58,237,0.35)" }}>
        {pending ? <><Spinner /> Signing in…</> : "Sign In"}
      </button>

      {/* Divider */}
      <div className="flex items-center gap-3">
        <div className="flex-1 h-px bg-[#EDE9F6]" />
        <span className="text-[#C4B5FD]" style={{ fontSize:"clamp(10px,1.2vh,12px)" }}>or</span>
        <div className="flex-1 h-px bg-[#EDE9F6]" />
      </div>

      <button type="button" onClick={google} disabled={pending}
        className="w-full flex items-center justify-center gap-2.5 font-medium text-[#13111A] bg-white border border-[#DDD6FE] rounded-[1.2vh] hover:bg-[#F5F3FF] transition-all disabled:opacity-60"
        style={{ padding:"1.5vh 2vh", fontSize:"clamp(12px,1.5vh,14px)" }}>
        <GoogleG /> Continue with Google
      </button>
    </form>
  )
}

// ─── Right panel — animated grid of images ────────────────────────────────────
function GridPanel() {
  // 28 placeholder tiles with subtle pattern instead of real images
  const tiles = Array.from({ length: 28 }, (_, i) => i)
  const shades = ["#EDE9FE","#DDD6FE","#F5F3FF","#E9D5FF","#C4B5FD","#F3E8FF","#EEF2FF","#E0E7FF"]

  return (
    <div className="relative w-full h-full overflow-hidden" style={{ background:"#F4F1FB" }}>
      {/* Fade left edge */}
      <div className="absolute inset-y-0 left-0 w-[6vw] z-10 pointer-events-none"
        style={{ background:"linear-gradient(to right, #F4F1FB, transparent)" }} />

      {/* Grid */}
      <div className="absolute inset-0 grid gap-[1vw] p-[1.5vw]"
        style={{ gridTemplateColumns:"repeat(4, 1fr)", gridTemplateRows:"repeat(4, 1fr)" }}>
        {tiles.slice(0,16).map((_, i) => (
          <div key={i} className="rounded-[1.2vw] overflow-hidden"
            style={{
              background: shades[i % shades.length],
              border:`1px solid ${shades[(i+2) % shades.length]}`,
              opacity: 0.7 + (i % 4) * 0.07
            }}>
            {/* Subtle inner detail */}
            <div className="w-full h-full flex items-center justify-center opacity-20">
              <div className="w-1/3 h-1/3 rounded-full"
                style={{ background:"#7C3AED" }} />
            </div>
          </div>
        ))}
      </div>

      {/* Overlay card */}
      <div className="absolute bottom-[4vh] left-[3vw] z-20">
        <div className="rounded-[2vh] border border-[#DDD6FE] px-[2vw] py-[2.5vh]"
          style={{
            background:"rgba(255,255,255,0.85)",
            backdropFilter:"blur(12px)",
            boxShadow:"0 4px 24px rgba(124,58,237,0.12)",
            maxWidth:"28vw"
          }}>
          <p className="font-bold text-[#13111A] leading-snug mb-[0.8vh]"
            style={{ fontSize:"clamp(13px,1.6vh,16px)" }}>
            Built for creators.
          </p>
          <p className="text-[#7C3AED] leading-relaxed"
            style={{ fontSize:"clamp(11px,1.3vh,13px)" }}>
            Join 14,000+ creators earning on their own terms.
          </p>
        </div>
      </div>
    </div>
  )
}

